import React, { useEffect, useState } from 'react';
import {
  Button,
  Checkbox,
  FormRowCol,
  Input,
  Modal,
  Select,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import { catalogUiSchemaService } from '../../services/catalogUiSchemaService';
import { useAppDispatch } from '../../store/hooks';
import type {
  CatalogUiField,
  CatalogUiListOptions,
  CatalogUiSchema,
  CatalogListHeightMode,
} from '../../types/catalogUiSchema';
import { isErpListUiSchemaKind } from '../../types/catalogUiSchema';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { buildBootstrapSchema } from './listUiSchemaBootstrap';
import erp from '../../styles/erpPage.module.css';
import schemaStyles from './ListUiSchemaEditorModal.module.css';

const HEIGHT_MODE_OPTIONS = [
  { value: 'auto', label: 'Tự động' },
  { value: 'fixed', label: 'Cố định' },
];

export interface ListUiSchemaEditorModalProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onSaved: (schema: CatalogUiSchema) => void;
  title?: string;
  /** Dòng list mẫu — seed field matrix khi chưa có record / GET lỗi. */
  sampleRow?: Record<string, unknown> | null;
}

function patchField(
  fields: CatalogUiField[],
  key: string,
  patch: Partial<Pick<CatalogUiField, 'list' | 'lookup' | 'proposal'>>,
): CatalogUiField[] {
  return fields.map(f => {
    if (f.key !== key) return f;
    return {
      ...f,
      ...(patch.list != null ? { list: patch.list } : {}),
      ...(patch.lookup != null ? { lookup: patch.lookup } : {}),
      ...(patch.proposal != null ? { proposal: patch.proposal } : {}),
    };
  });
}

const ListGridConfigBlock: React.FC<{
  list: CatalogUiListOptions;
  onPatch: (patch: Partial<CatalogUiListOptions>) => void;
  testIdPrefix: string;
}> = ({ list, onPatch, testIdPrefix }) => (
  <div className={schemaStyles.gridBlock} data-testid={`${testIdPrefix}-list-grid-config`}>
    <div className={schemaStyles.gridBlockTitle}>Bảng danh sách</div>
    <FormRowCol cols={4}>
      <FormRowCol.Item label="Chiều cao bảng">
        <Select
          value={list.heightMode ?? 'auto'}
          options={HEIGHT_MODE_OPTIONS}
          data-testid={`${testIdPrefix}-list-config-height-mode`}
          onChange={e => onPatch({ heightMode: e.target.value as CatalogListHeightMode })}
        />
      </FormRowCol.Item>
      <FormRowCol.Item label="Chiều cao (CSS)" hidden={(list.heightMode ?? 'auto') !== 'fixed'}>
        <Input
          value={list.height ?? '420px'}
          placeholder="420px"
          data-testid={`${testIdPrefix}-list-config-height`}
          onChange={e => onPatch({ height: e.target.value || '420px' })}
        />
      </FormRowCol.Item>
      <FormRowCol.Item variant="control">
        <Checkbox
          label="Giữ header khi scroll"
          checked={list.stickyHeader ?? true}
          data-testid={`${testIdPrefix}-list-config-sticky`}
          onChange={e => onPatch({ stickyHeader: e.target.checked })}
        />
      </FormRowCol.Item>
      <FormRowCol.Item variant="control">
        <Checkbox
          label="Cho phép kéo độ rộng cột"
          checked={list.resizableColumns ?? true}
          data-testid={`${testIdPrefix}-list-config-resizable`}
          onChange={e => onPatch({ resizableColumns: e.target.checked })}
        />
      </FormRowCol.Item>
    </FormRowCol>
  </div>
);

export const ListUiSchemaEditorModal: React.FC<ListUiSchemaEditorModalProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onSaved,
  title = 'Cấu hình hiển thị danh sách',
  sampleRow,
}) => {
  const dispatch = useAppDispatch();
  const [draft, setDraft] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [bootstrapDraft, setBootstrapDraft] = useState(false);
  const erpListKind = isErpListUiSchemaKind(catalogKind);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    setLoading(true);
    setBootstrapDraft(false);
    catalogUiSchemaService
      .get(catalogKind, true)
      .then(data => {
        if (!cancelled) {
          setDraft(data);
          setBootstrapDraft(false);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setDraft(buildBootstrapSchema(catalogKind, sampleRow));
          setBootstrapDraft(true);
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => { cancelled = true; };
  }, [isOpen, catalogKind, sampleRow]);

  useEffect(() => {
    if (!isOpen || loading || draft) return;
    setDraft(buildBootstrapSchema(catalogKind, sampleRow));
    setBootstrapDraft(true);
  }, [isOpen, loading, draft, catalogKind, sampleRow]);

  const editableFields = draft?.fields.filter(f => f.configurable !== false) ?? [];

  const updateList = (key: string, visible: boolean, width?: string) => {
    setDraft(prev => {
      if (!prev) return prev;
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          list: {
            visible,
            order: prev.fields.find(f => f.key === key)?.list?.order ?? 0,
            width: width ?? prev.fields.find(f => f.key === key)?.list?.width ?? undefined,
            variant: prev.fields.find(f => f.key === key)?.list?.variant ?? undefined,
          },
        }),
      };
    });
  };

  const handleSave = async () => {
    if (!draft) return;
    setSaving(true);
    try {
      const saved = await catalogUiSchemaService.save(catalogKind, {
        schemaVersion: draft.schemaVersion,
        fields: draft.fields.filter(f => f.configurable !== false),
        lookup: draft.lookup,
        list: draft.list,
        hintText: draft.hintText ?? null,
      });
      dispatchAppToast(dispatch, { message: 'Đã lưu cấu hình hiển thị', type: 'success' });
      onSaved(saved);
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Lưu cấu hình thất bại'),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} size="lg" fillContent>
      <div
        className={[schemaStyles.shell, schemaStyles.shellFill].join(' ')}
        data-testid={`${testIdPrefix}-schema-editor`}
      >
        {loading && <p>Đang tải…</p>}
        {!loading && draft && (
          <>
            <div className={schemaStyles.body}>
              <p className={schemaStyles.gridBlockTitle}>
                Chọn cột hiển thị, hint và tùy chọn bảng — parity danh mục Tài khoản.
                {bootstrapDraft ? (
                  <>
                    {' '}
                    Đang dùng mẫu từ dòng danh sách — chưa có cấu hình đã lưu;{' '}
                    <strong>Lưu</strong> sẽ ghi nhận lần đầu.
                  </>
                ) : null}
              </p>
              {erpListKind ? (
                <div className={schemaStyles.configSection}>
                  <div className={erp.field}>
                    <label>Hint header</label>
                    <Input
                      value={draft.hintText ?? ''}
                      placeholder="Mô tả ngắn dưới tiêu đề trang"
                      data-testid={`${testIdPrefix}-schema-hint-text`}
                      onChange={e => setDraft(prev => prev ? { ...prev, hintText: e.target.value } : prev)}
                    />
                  </div>
                  <ListGridConfigBlock
                    testIdPrefix={testIdPrefix}
                    list={draft.list}
                    onPatch={patch => setDraft(prev => prev ? { ...prev, list: { ...prev.list, ...patch } } : prev)}
                  />
                </div>
              ) : null}
              <div className={schemaStyles.detailScroll}>
                <table className={erp.table}>
                  <thead>
                    <tr>
                      <th>Trường</th>
                      <th>List</th>
                      <th>Rộng list</th>
                      {!erpListKind && (
                        <>
                          <th>Lookup</th>
                          <th>Rộng lookup</th>
                          <th>Đề xuất</th>
                        </>
                      )}
                    </tr>
                  </thead>
                  <tbody>
                    {editableFields.map(f => (
                      <tr key={f.key}>
                        <td>
                          <strong>{f.label}</strong>
                          <br />
                          <code className={schemaStyles.schemaFieldKey}>{f.key}</code>
                        </td>
                        <td>
                          <Checkbox
                            id={`${testIdPrefix}-schema-list-cb-${f.key}`}
                            aria-label={`Hiển thị ${f.label} trên danh sách`}
                            checked={!!f.list?.visible}
                            data-testid={`${testIdPrefix}-schema-list-${f.key}`}
                            onChange={e => updateList(f.key, e.target.checked)}
                          />
                        </td>
                        <td>
                          <Input
                            value={f.list?.width ?? ''}
                            placeholder="8rem / 1fr"
                            disabled={!f.list?.visible}
                            data-testid={`${testIdPrefix}-schema-list-w-${f.key}`}
                            onChange={e => updateList(f.key, !!f.list?.visible, e.target.value)}
                          />
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
            <div className={schemaStyles.footer}>
              <div className={schemaStyles.footerActions}>
                <Button variant="secondary" onClick={onClose}>Hủy</Button>
                <Button
                  variant="primary"
                  disabled={saving}
                  data-testid={`${testIdPrefix}-schema-save`}
                  onClick={() => void handleSave()}
                >
                  {saving ? 'Đang lưu…' : 'Lưu cấu hình'}
                </Button>
              </div>
            </div>
          </>
        )}
      </div>
    </Modal>
  );
};
