import type { CatalogUiField, CatalogUiSchema } from '../../types/catalogUiSchema';

export function listVisibleFields(schema: CatalogUiSchema | null): CatalogUiField[] {
  if (!schema) return [];
  return schema.fields
    .filter(f => f.list?.visible)
    .sort((a, b) => (a.list?.order ?? 0) - (b.list?.order ?? 0));
}
